from typing import List, Dict, Any, Optional


VALID_OPERATORS = {'=', '>', '<', '>=', '<=', '!=', 'LIKE', 'NOT LIKE', 'IN', 'NOT IN', 'BETWEEN', 'IS NULL', 'IS NOT NULL'}
VALID_LOGICAL_OPERATORS = {'AND', 'OR'}


def validate_field_name(field: str) -> bool:
    """Validate that a field name contains only safe characters."""
    return bool(re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', field))


def validate_table_name(table: str) -> bool:
    """Validate that a table name contains only safe characters."""
    return bool(re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', table))


def validate_operator(op: str) -> bool:
    """Validate that the operator is in the allowed set."""
    return op.upper() in VALID_OPERATORS


def build_condition(condition: Dict[str, Any], params: List[Any], param_index: int) -> tuple:
    """
    Build a single SQL condition clause with parameterized values.
    
    Returns:
        Tuple of (condition_string, updated_param_index)
    """
    field = condition.get('field', '')
    op = condition.get('op', '').upper()
    value = condition.get('value')

    if not validate_field_name(field):
        raise ValueError(f"Invalid field name: '{field}'. Field names must contain only alphanumeric characters and underscores.")

    if not validate_operator(op):
        raise ValueError(f"Invalid operator: '{op}'. Allowed operators: {VALID_OPERATORS}")

    # Handle operators that don't need a value
    if op == 'IS NULL':
        return f'"{field}" IS NULL', param_index
    elif op == 'IS NOT NULL':
        return f'"{field}" IS NOT NULL', param_index

    # Handle BETWEEN operator
    if op == 'BETWEEN':
        if not isinstance(value, (list, tuple)) or len(value) != 2:
            raise ValueError(f"BETWEEN operator requires a list/tuple of exactly 2 values, got: {value}")
        params.append(value[0])
        params.append(value[1])
        clause = f'"{field}" BETWEEN ? AND ?'
        return clause, param_index + 2

    # Handle IN / NOT IN operator
    if op in ('IN', 'NOT IN'):
        if not isinstance(value, (list, tuple)) or len(value) == 0:
            raise ValueError(f"{op} operator requires a non-empty list/tuple of values, got: {value}")
        placeholders = ', '.join(['?'] * len(value))
        params.extend(value)
        clause = f'"{field}" {op} ({placeholders})'
        return clause, param_index + len(value)

    # Handle standard operators
    if value is None:
        raise ValueError(f"Operator '{op}' requires a value.")

    params.append(value)
    clause = f'"{field}" {op} ?'
    return clause, param_index + 1


def build_query(
    table: str,
    conditions: List[Dict[str, Any]],
    logical_operator: str = 'AND',
    select_fields: Optional[List[str]] = None,
    order_by: Optional[List[Dict[str, str]]] = None,
    limit: Optional[int] = None,
    offset: Optional[int] = None,
    group_by: Optional[List[str]] = None
) -> tuple:
    """
    Build a complete SQL SELECT query dynamically with parameterized values.
    
    Args:
        table: Table name to query
        conditions: List of condition dicts with 'field', 'op', 'value' keys.
                    Can also contain nested conditions with 'conditions' and 'logic' keys.
        logical_operator: How to combine top-level conditions ('AND' or 'OR')
        select_fields: List of field names to select (None for *)
        order_by: List of dicts with 'field' and optional 'direction' ('ASC'/'DESC')
        limit: Maximum number of rows to return
        offset: Number of rows to skip
        group_by: List of field names to group by
    
    Returns:
        Tuple of (query_string, params_list)
    """
    if not validate_table_name(table):
        raise ValueError(f"Invalid table name: '{table}'")

    if logical_operator.upper() not in VALID_LOGICAL_OPERATORS:
        raise ValueError(f"Invalid logical operator: '{logical_operator}'. Use 'AND' or 'OR'.")

    logical_operator = logical_operator.upper()
    params = []

    # Build SELECT clause
    if select_fields:
        for f in select_fields:
            if not validate_field_name(f):
                raise ValueError(f"Invalid select field name: '{f}'")
        select_clause = ', '.join(f'"{f}"' for f in select_fields)
    else:
        select_clause = '*'

    query = f'SELECT {select_clause} FROM "{table}"'

    # Build WHERE clause
    if conditions:
        where_parts = []
        param_index = 0

        for condition in conditions:
            # Support nested condition groups
            if 'conditions' in condition:
                nested_logic = condition.get('logic', 'AND').upper()
                if nested_logic not in VALID_LOGICAL_OPERATORS:
                    raise ValueError(f"Invalid nested logical operator: '{nested_logic}'")
                nested_parts = []
                for nested_cond in condition['conditions']:
                    clause, param_index = build_condition(nested_cond, params, param_index)
                    nested_parts.append(clause)
                where_parts.append(f'({f" {nested_logic} ".join(nested_parts)})')
            else:
                clause, param_index = build_condition(condition, params, param_index)
                where_parts.append(clause)

        where_clause = f' {logical_operator} '.join(where_parts)
        query += f' WHERE {where_clause}'

    # Build GROUP BY clause
    if group_by:
        for f in group_by:
            if not validate_field_name(f):
                raise ValueError(f"Invalid group by field name: '{f}'")
        group_clause = ', '.join(f'"{f}"' for f in group_by)
        query += f' GROUP BY {group_clause}'

    # Build ORDER BY clause
    if order_by:
        order_parts = []
        for item in order_by:
            field = item.get('field', '')
            direction = item.get('direction', 'ASC').upper()
            if not validate_field_name(field):
                raise ValueError(f"Invalid order by field name: '{field}'")
            if direction not in ('ASC', 'DESC'):
                raise ValueError(f"Invalid sort direction: '{direction}'. Use 'ASC' or 'DESC'.")
            order_parts.append(f'"{field}" {direction}')
        query += f' ORDER BY {", ".join(order_parts)}'

    # Build LIMIT/OFFSET clause
    if limit is not None:
        if not isinstance(limit, int) or limit < 0:
            raise ValueError(f"Limit must be a non-negative integer, got: {limit}")
        query += f' LIMIT ?'
        params.append(limit)

    if offset is not None:
        if not isinstance(offset, int) or offset < 0:
            raise ValueError(f"Offset must be a non-negative integer, got: {offset}")
        if limit is None:
            query += ' LIMIT -1'  # SQLite requires LIMIT before OFFSET
        query += f' OFFSET ?'
        params.append(offset)

    return query, params


def search(
    conditions: List[Dict[str, Any]],
    table: str = 'users',
    logical_operator: str = 'AND',
    select_fields: Optional[List[str]] = None,
    order_by: Optional[List[Dict[str, str]]] = None,
    limit: Optional[int] = None,
    offset: Optional[int] = None,
    group_by: Optional[List[str]] = None,
    db_path: str = ':memory:',
    connection: Optional[sqlite3.Connection] = None
) -> List[Dict[str, Any]]:
    """
    Execute a dynamic search query against a SQLite database.
    
    Args:
        conditions: List of search conditions
        table: Table name to search
        logical_operator: 'AND' or 'OR' to combine conditions
        select_fields: Fields to return (None for all)
        order_by: Sort specification
        limit: Max rows to return
        offset: Rows to skip
        group_by: Fields to group by
        db_path: Path to SQLite database file
        connection: Optional existing database connection
    
    Returns:
        List of dictionaries representing matching rows
    """
    query, params = build_query(
        table=table,
        conditions=conditions,
        logical_operator=logical_operator,
        select_fields=select_fields,
        order_by=order_by,
        limit=limit,
        offset=offset,
        group_by=group_by
    )

    own_connection = False
    if connection is None:
        connection = sqlite3.connect(db_path)
        own_connection = True

    try:
        connection.row_factory = sqlite3.Row
        cursor = connection.cursor()
        cursor.execute(query, params)
        rows = cursor.fetchall()
        results = [dict(row) for row in rows]
        return results
    finally:
        if own_connection:
            connection.close()


